class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int leftIndex = findLeftIndex(nums, pivot);
        int rightIndex = findRightIndex(nums, pivot);
        int[] result = new int[rightIndex - leftIndex + 1];
        for (int i = 0; i < result.length; i++) {
            result[i] = nums[leftIndex + i];
        }
        return result;
    }

    private int findLeftIndex(int[] nums, int pivot) {
        int leftIndex = 0;
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] < pivot) {
                leftIndex++;
            }
        }
        return leftIndex;
    }

    private int findRightIndex(int[] nums, int pivot) {
        int rightIndex = nums.length - 1;
        for (int i = nums.length - 1; i >= 0; i--) {
            if (nums[i] > pivot) {
                rightIndex--;
            }
        }
        return rightIndex;
    }
}
